def combination_sum2(candidates, target):
    candidates.sort()
    res, path = [], []
    def dfs(start, remain):
        if remain == 0:
            res.append(path[:])
            return
        for i in range(start, len(candidates)):
            if i > start and candidates[i] == candidates[i - 1]:
                continue
            x = candidates[i]
            if x > remain:
                break
            path.append(x)
            dfs(i + 1, remain - x)
            path.pop()
    dfs(0, target)
    return res

